Install fuse.js in apps/client and create the use-palette-search.ts hook that integrates Fuse.js fuzzy search with category prefix detection.

## Steps

1. Install fuse.js in apps/client:
   ```bash
   pnpm --filter=@dorkos/client add fuse.js@^7.0.0
   ```

2. Create `apps/client/src/layers/features/command-palette/model/use-palette-search.ts`:

```tsx
import Fuse from 'fuse.js';
import { useMemo } from 'react';
import type { AgentPathEntry } from '@dorkos/shared/mesh-schemas';

export interface SearchableItem {
  id: string;
  name: string;
  type: 'agent' | 'feature' | 'command' | 'quick-action' | 'suggestion';
  keywords?: string[];
  data: AgentPathEntry | FeatureItem | CommandItemData | QuickActionItem;
}

export interface SearchResult {
  item: SearchableItem;
  matches: Fuse.FuseResultMatch[] | undefined;
}

interface FeatureItem {
  id: string;
  label: string;
  icon: string;
  shortcut?: string;
  action: string;
}

interface CommandItemData {
  name: string;
  description?: string;
}

interface QuickActionItem {
  id: string;
  label: string;
  icon: string;
  action: string;
}

const FUSE_OPTIONS: Fuse.IFuseOptions<SearchableItem> = {
  keys: ['name', 'keywords'],
  includeMatches: true,
  threshold: 0.3,
  distance: 100,
  minMatchCharLength: 1,
};

/**
 * Fuse.js-powered fuzzy search with category prefix detection.
 *
 * Prefix @ filters agents only. Prefix > filters commands only.
 * No prefix searches all categories.
 *
 * @param items - All searchable items across categories
 * @param search - Raw search string from the input (may include prefix)
 */
export function usePaletteSearch(items: SearchableItem[], search: string) {
  const { prefix, term } = useMemo(() => parsePrefix(search), [search]);

  const filteredByPrefix = useMemo(() => {
    if (prefix === '@') return items.filter(i => i.type === 'agent');
    if (prefix === '>') return items.filter(i => i.type === 'command');
    return items;
  }, [items, prefix]);

  const fuse = useMemo(
    () => new Fuse(filteredByPrefix, FUSE_OPTIONS),
    [filteredByPrefix]
  );

  const results: SearchResult[] = useMemo(() => {
    if (!term) {
      return filteredByPrefix.map(item => ({ item, matches: undefined }));
    }
    return fuse.search(term);
  }, [fuse, term, filteredByPrefix]);

  return { results, prefix, term };
}

/** @internal Exported for testing only. */
export function parsePrefix(search: string): { prefix: string | null; term: string } {
  if (search.startsWith('@')) return { prefix: '@', term: search.slice(1) };
  if (search.startsWith('>')) return { prefix: '>', term: search.slice(1) };
  return { prefix: null, term: search };
}
```

3. Create test file `apps/client/src/layers/features/command-palette/model/__tests__/use-palette-search.test.ts`:

```tsx
import { describe, it, expect } from 'vitest';
import { renderHook } from '@testing-library/react';
import { usePaletteSearch, parsePrefix } from '../use-palette-search';
import type { SearchableItem } from '../use-palette-search';

const mockItems: SearchableItem[] = [
  { id: 'agent-1', name: 'Auth Service', type: 'agent', keywords: ['/projects/auth'], data: { id: 'agent-1', name: 'Auth Service', projectPath: '/projects/auth' } as any },
  { id: 'agent-2', name: 'API Gateway', type: 'agent', keywords: ['/projects/api'], data: { id: 'agent-2', name: 'API Gateway', projectPath: '/projects/api' } as any },
  { id: 'feature-1', name: 'Pulse Scheduler', type: 'feature', data: { id: 'pulse', label: 'Pulse Scheduler', icon: 'Clock', action: 'openPulse' } as any },
  { id: 'cmd-1', name: '/hello', type: 'command', keywords: ['greeting'], data: { name: '/hello', description: 'Say hello' } as any },
];

describe('parsePrefix', () => {
  it('detects @ prefix for agents', () => {
    expect(parsePrefix('@auth')).toEqual({ prefix: '@', term: 'auth' });
  });

  it('detects > prefix for commands', () => {
    expect(parsePrefix('>hello')).toEqual({ prefix: '>', term: 'hello' });
  });

  it('returns null prefix for plain search', () => {
    expect(parsePrefix('auth')).toEqual({ prefix: null, term: 'auth' });
  });

  it('handles prefix with empty term', () => {
    expect(parsePrefix('@')).toEqual({ prefix: '@', term: '' });
  });
});

describe('usePaletteSearch', () => {
  it('returns all items when search is empty', () => {
    const { result } = renderHook(() => usePaletteSearch(mockItems, ''));
    expect(result.current.results).toHaveLength(4);
    expect(result.current.results[0].matches).toBeUndefined();
  });

  it('filters by @ prefix (agents only)', () => {
    const { result } = renderHook(() => usePaletteSearch(mockItems, '@'));
    expect(result.current.results.every(r => r.item.type === 'agent')).toBe(true);
    expect(result.current.prefix).toBe('@');
  });

  it('filters by > prefix (commands only)', () => {
    const { result } = renderHook(() => usePaletteSearch(mockItems, '>'));
    expect(result.current.results.every(r => r.item.type === 'command')).toBe(true);
    expect(result.current.prefix).toBe('>');
  });

  it('returns match indices for highlighting', () => {
    const { result } = renderHook(() => usePaletteSearch(mockItems, 'auth'));
    const authResult = result.current.results.find(r => r.item.id === 'agent-1');
    expect(authResult).toBeDefined();
    expect(authResult!.matches).toBeDefined();
    expect(authResult!.matches!.length).toBeGreaterThan(0);
  });

  it('handles typo-tolerant matching', () => {
    const { result } = renderHook(() => usePaletteSearch(mockItems, 'autth'));
    expect(result.current.results).toBeDefined();
  });

  it('returns empty results when no match', () => {
    const { result } = renderHook(() => usePaletteSearch(mockItems, 'zzzznotexist'));
    expect(result.current.results).toHaveLength(0);
  });

  it('scores exact matches higher than partial matches', () => {
    const { result } = renderHook(() => usePaletteSearch(mockItems, 'Auth Service'));
    if (result.current.results.length > 0) {
      expect(result.current.results[0].item.id).toBe('agent-1');
    }
  });
});
```

## Acceptance Criteria
- [ ] fuse.js@^7.0.0 installed in apps/client package.json
- [ ] use-palette-search.ts created with Fuse.js integration, prefix parsing, and proper memoization
- [ ] SearchableItem and SearchResult interfaces exported for use by other modules
- [ ] parsePrefix correctly handles @, >, and no-prefix cases
- [ ] All 11 unit tests in use-palette-search.test.ts pass
- [ ] Fuse instance is memoized per item list change (not recreated on every search)

Create the HighlightedText component that renders React nodes from Fuse.js match indices, bolding matched characters. All content is rendered via React createElement -- no raw HTML injection is used.

## Steps

1. Create `apps/client/src/layers/features/command-palette/ui/HighlightedText.tsx`:

```tsx
interface HighlightedTextProps {
  /** The full text string to render */
  text: string;
  /** Fuse.js match indices -- array of [start, end] pairs where end is inclusive */
  indices?: readonly [number, number][];
  className?: string;
}

/**
 * Render text with matched character ranges bolded.
 *
 * Builds React nodes from Fuse.js match index pairs.
 * Safe by construction -- all content goes through React's createElement pipeline.
 *
 * @param text - Full text to render
 * @param indices - Fuse.js match ranges where each pair is [start, endInclusive]
 * @param className - Optional CSS class for the wrapper span
 */
export function HighlightedText({ text, indices, className }: HighlightedTextProps) {
  if (!indices || indices.length === 0) {
    return <span className={className}>{text}</span>;
  }

  const parts: React.ReactNode[] = [];
  let lastIdx = 0;

  for (let i = 0; i < indices.length; i++) {
    const [start, end] = indices[i];
    // end is inclusive in Fuse.js
    const matchEnd = end + 1;

    if (lastIdx < start) {
      parts.push(<span key={`p-${i}`}>{text.slice(lastIdx, start)}</span>);
    }
    parts.push(
      <mark key={`m-${i}`} className="bg-transparent text-foreground font-semibold">
        {text.slice(start, matchEnd)}
      </mark>
    );
    lastIdx = matchEnd;
  }

  if (lastIdx < text.length) {
    parts.push(<span key="tail">{text.slice(lastIdx)}</span>);
  }

  return <span className={className}>{parts}</span>;
}
```

