    const { result } = renderHook(() => useAgentFrecency());
    for (let i = 0; i < 15; i++) {
      act(() => { result.current.recordUsage('agent-1'); });
    }
    const records = JSON.parse(store['dorkos:agent-frecency-v2']) as FrecencyRecord[];
    expect(records[0].timestamps.length).toBeLessThanOrEqual(10);
    expect(records[0].totalCount).toBe(15);
  });

  it('returns agents sorted by frecency score', async () => {
    const { useAgentFrecency } = await import('../use-agent-frecency');
    const { result } = renderHook(() => useAgentFrecency());
    act(() => { result.current.recordUsage('agent-1'); });
    act(() => { result.current.recordUsage('agent-2'); });
    act(() => { result.current.recordUsage('agent-2'); });
    act(() => { result.current.recordUsage('agent-2'); });
    const sorted = result.current.getSortedAgentIds(['agent-1', 'agent-2', 'agent-3']);
    expect(sorted[0]).toBe('agent-2');
    expect(sorted[1]).toBe('agent-1');
  });
});
```

## Acceptance Criteria
- [ ] New storage key dorkos:agent-frecency-v2 used (old key untouched)
- [ ] FrecencyRecord interface with timestamps: number[] and totalCount: number
- [ ] calcFrecencyScore implements correct bucket scoring (100/80/60/40/20/10/0)
- [ ] Formula: totalCount * bucketSum / min(timestamps.length, 10)
- [ ] Timestamps array capped at 10 entries, most recent first
- [ ] useSyncExternalStore pattern and public API (entries, recordUsage, getSortedAgentIds) preserved
- [ ] All 15+ unit tests pass
- [ ] Graceful degradation when localStorage is unavailable

Update CommandPaletteDialog.tsx to use shouldFilter={false} on the cmdk Command component and drive all filtering/scoring through the new usePaletteSearch hook. Render results with HighlightedText for match highlighting. Add > command prefix support.

## Steps

1. Update `apps/client/src/layers/features/command-palette/model/use-palette-items.ts` to export SearchableItem-compatible data. Add a new `searchableItems` field to the PaletteItems return value that converts all palette groups into a flat SearchableItem[] array:

```tsx
import type { SearchableItem } from './use-palette-search';

// Add to PaletteItems interface:
export interface PaletteItems {
  recentAgents: AgentPathEntry[];
  allAgents: AgentPathEntry[];
  features: FeatureItem[];
  commands: CommandItemData[];
  quickActions: QuickActionItem[];
  searchableItems: SearchableItem[];
  isLoading: boolean;
}

// Inside usePaletteItems, add:
const searchableItems = useMemo(() => {
  const items: SearchableItem[] = [];
  for (const agent of allAgents) {
    items.push({
      id: agent.id,
      name: agent.name,
      type: 'agent',
      keywords: [agent.projectPath, agent.id],
      data: agent,
    });
  }
  for (const f of FEATURES) {
    items.push({ id: f.id, name: f.label, type: 'feature', data: f });
  }
  for (const cmd of commands) {
    items.push({
      id: `cmd-${cmd.name}`,
      name: cmd.name,
      type: 'command',
      keywords: cmd.description ? [cmd.description] : undefined,
      data: cmd,
    });
